import 'package:equatable/equatable.dart';

enum PaymentMethod { applePay, googlePay, creditCard, inAppPurchase, stripe }

enum PaymentStatus {
  idle,
  processing,
  completed,
  failed,
  cancelled,
  refunded,
  pending,
  requiresAction,
}

enum TransactionType { purchase, subscription, consumable, nonConsumable }

class PaymentResult extends Equatable {
  final String transactionId;
  final PaymentStatus status;
  final double amount;
  final String currency;
  final PaymentMethod method;
  final DateTime timestamp;
  final String? errorMessage;
  final Map<String, dynamic>? metadata;

  const PaymentResult({
    required this.transactionId,
    required this.status,
    required this.amount,
    required this.currency,
    required this.method,
    required this.timestamp,
    this.errorMessage,
    this.metadata,
  });

  bool get isSuccessful => status == PaymentStatus.completed;

  Map<String, dynamic> toJson() => {
    'transactionId': transactionId,
    'status': status.name,
    'amount': amount,
    'currency': currency,
    'method': method.name,
    'timestamp': timestamp.toIso8601String(),
    'errorMessage': errorMessage,
    'metadata': metadata,
  };

  factory PaymentResult.fromJson(Map<String, dynamic> json) => PaymentResult(
    transactionId: json['transactionId'],
    status: PaymentStatus.values.byName(json['status']),
    amount: (json['amount'] as num).toDouble(),
    currency: json['currency'],
    method: PaymentMethod.values.byName(json['method']),
    timestamp: DateTime.parse(json['timestamp']),
    errorMessage: json['errorMessage'],
    metadata: json['metadata'],
  );

  @override
  List<Object?> get props => [transactionId, status, amount, currency, method, timestamp];
}

