class PaymentSecurity {
  static final PaymentSecurity _instance = PaymentSecurity._internal();
  factory PaymentSecurity() => _instance;
  PaymentSecurity._internal();

  // Simulates secure storage - in production use FlutterSecureStorage
  final Map<String, String> _secureStore = {};

  /// Tokenize sensitive card data - never store raw card numbers
  String tokenizeCardNumber(String cardNumber) {
    final sanitized = cardNumber.replaceAll(RegExp(r'\s+'), '');
    _validateCardNumber(sanitized);

    // In production: send to payment gateway for tokenization
    // NEVER store raw card numbers locally
    final token = _generateToken();
    final masked = _maskCardNumber(sanitized);

    _secureStore['card_token_$token'] = masked;
    return token;
  }

  String tokenizeCvv(String cvv) {
    if (cvv.length < 3 || cvv.length > 4) {
      throw const PCIComplianceException('Invalid CVV length');
    }
    // CVV should NEVER be stored - only tokenized for single transaction
    return _generateToken();
  }

  String _maskCardNumber(String number) {
    if (number.length < 8) return '****';
    return '${'*' * (number.length - 4)}${number.substring(number.length - 4)}';
  }

  String getMaskedNumber(String token) {
    return _secureStore['card_token_$token'] ?? '****';
  }

  void _validateCardNumber(String number) {
    if (number.length < 13 || number.length > 19) {
      throw const PaymentValidationException('Invalid card number length');
    }
    if (!_luhnCheck(number)) {
      throw const PaymentValidationException('Invalid card number');
    }
  }

  bool _luhnCheck(String number) {
    int sum = 0;
    bool alternate = false;
    for (int i = number.length - 1; i >= 0; i--) {
      int digit = int.parse(number[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  String _generateToken() {
    final random = Random.secure();
    final bytes = List<int>.generate(32, (_) => random.nextInt(256));
    return base64Url.encode(Uint8List.fromList(bytes)).substring(0, 32);
  }

  /// Generate idempotency key for transaction deduplication
  String generateIdempotencyKey() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final random = Random.secure().nextInt(999999);
    return 'idem_${timestamp}_$random';
  }

  /// Encrypt payload for transit
  String encryptPayload(Map<String, dynamic> payload) {
    // In production: use RSA/AES encryption with server's public key
    final jsonStr = jsonEncode(payload);
    return base64Encode(utf8.encode(jsonStr));
  }

