  /// Securely store API keys
  Future<void> storeApiKey(String key, String value) async {
    // In production: use FlutterSecureStorage
    _secureStore[key] = value;
  }

  Future<String?> getApiKey(String key) async {
    return _secureStore[key];
  }

  /// Clear all sensitive data
  void clearSensitiveData() {
    _secureStore.clear();
  }

  /// Validate that we're not logging sensitive data
  Map<String, dynamic> sanitizeForLogging(Map<String, dynamic> data) {
    final sanitized = Map<String, dynamic>.from(data);
    const sensitiveKeys = ['cardNumber', 'cvv', 'cvc', 'pin', 'password', 'secret'];
    for (final key in sensitiveKeys) {
      if (sanitized.containsKey(key)) {
        sanitized[key] = '***REDACTED***';
      }
    }
    return sanitized;
  }
